                    {postArray.map((post) => {
                        const userId = post.users?.id;
                        const color = getStarColor(userId);
                        const likeCount = Array.isArray(post.likes) && post.likes[0]?.count != null
                            ? post.likes[0].count
                            : 0;
                        const radius = getStarRadius(likeCount);
                        const isPulsing = pulsingId === post.id;

                        return (
                            <Group
                                key={post.id}
                                x={post.universe_x}
                                y={post.universe_y}
                                onClick={() => handleStarClick(post)}
                                onTap={() => handleStarClick(post)}
