 19→const userHomeCoords = (userId) => {
 20→    const mid = Math.floor(userId.length / 2);
 21→    const xHash = Math.abs(simpleHash(userId.slice(0, mid)));
 22→    const yHash = Math.abs(simpleHash(userId.slice(mid)));
 23→    const x = (xHash % 50001) / 50000 * 50000 - 25000;
 24→    const y = (yHash % 50001) / 50000 * 50000 - 25000;
 25→    return {x, y};
 26→};
