 35→async function backfill(){
 36→    console.log('Fetching posts with no universe coordinates...');
 37→
 38→    const {data: posts, error} = await supabase
 39→        .from('journals')
 40→        .select('id, user_id, created_at')
 41→        .is('universe_x', null)
 42→        .order('user_id', {ascending: true})
 43→        .order('created_at', {ascending: true});
 44→
 45→    if(error){
 46→        console.error('Error fetching posts:', error.message);
 47→        process.exit(1);
 48→    }
 49→
 50→    if(!posts || posts.length === 0){
 51→        console.log('No posts to backfill.');
 52→        process.exit(0);
 53→    }
 54→
 55→    console.log(`Found ${posts.length} posts to backfill.`);
 56→
 57→    const grouped = {};
 58→    for(const post of posts){
 59→        if(!grouped[post.user_id]) grouped[post.user_id] = [];
 60→        grouped[post.user_id].push(post);
 61→    }
 62→
 63→    let updated = 0;
 64→    let failed = 0;
 65→
 66→    for(const [userId, userPosts] of Object.entries(grouped)){
 67→        const {count: existingCount} = await supabase
 68→            .from('journals')
 69→            .select('id', {count: 'exact', head: true})
 70→            .eq('user_id', userId)
 71→            .not('universe_x', 'is', null);
 72→
 73→        const startIndex = existingCount || 0;
 74→        const home = userHomeCoords(userId);
 75→
 76→        for(let i = 0; i < userPosts.length; i++){
 77→            const offset = spiralLayout(startIndex + i);
 78→            const universe_x = home.x + offset.dx;
 79→            const universe_y = home.y + offset.dy;
 80→
 81→            const {error: updateError} = await supabase
 82→                .from('journals')
 83→                .update({universe_x, universe_y})
 84→                .eq('id', userPosts[i].id);
 85→
 86→            if(updateError){
 87→                console.error(`Failed to update post ${userPosts[i].id}:`, updateError.message);
 88→                failed++;
 89→            } else {
 90→                updated++;
 91→            }
 92→        }
 93→    }
 94→
 95→    console.log(`Backfill complete. Updated: ${updated}, Failed: ${failed}`);
 96→    process.exit(0);
 97→}
