 28→const getStarColor = (userId) => {
 29→    if(!userId) return STAR_COLORS[0];
 30→    return STAR_COLORS[simpleHash(userId) % STAR_COLORS.length];
 31→};
 32→
 33→const getStarRadius = (likeCount) => {
 34→    const likes = Math.min(likeCount || 0, 20);
 35→    return 6 + likes * 0.3;
 36→};
