 65→// Zoom level where individual stars in your galaxy are comfortable to see
 66→const HOME_SCALE = 0.8;
 67→// Zoom level for guests — zoomed out to see everything
 68→const GUEST_SCALE = 0.05;
 69→
 70→const computeInitialCamera = (userId) => {
 71→    const w = window.innerWidth;
 72→    const h = window.innerHeight;
 73→    if(!userId){
 74→        return {x: w / 2, y: h / 2, scale: GUEST_SCALE};
 75→    }
 76→    const home = userHomeCoords(userId);
 77→    // Stage position so that world coord (home.x, home.y) maps to screen center
 78→    return {
 79→        x: w / 2 - home.x * HOME_SCALE,
 80→        y: h / 2 - home.y * HOME_SCALE,
 81→        scale: HOME_SCALE
 82→    };
 83→};
