 85→const Universe = () => {
 86→    const navigate = useNavigate();
 87→    const {user} = useAuth();
 88→    const userId = user?.userData?.[0]?.id || null;
 89→
 90→    const containerRef = useRef(null);
 91→    const stageRef = useRef(null);
 92→    const debounceRef = useRef(null);
 93→    const lastPinchDist = useRef(null);
 94→
 95→    const initial = useMemo(() => computeInitialCamera(userId), [userId]);
 96→    const [stageSize, setStageSize] = useState({width: window.innerWidth, height: window.innerHeight});
 97→    const [stagePos, setStagePos] = useState({x: initial.x, y: initial.y});
 98→    const [stageScale, setStageScale] = useState(initial.scale);
 99→    const [isDragging, setIsDragging] = useState(false);
100→    const [posts, setPosts] = useState(new Map());
101→    const [selectedPost, setSelectedPost] = useState(null);
102→    const [pulsingId, setPulsingId] = useState(null);
103→
104→    // Resize handler
105→    useEffect(() => {
106→        const handleResize = () => {
107→            setStageSize({width: window.innerWidth, height: window.innerHeight});
108→        };
109→        window.addEventListener('resize', handleResize);
110→        return () => window.removeEventListener('resize', handleResize);
111→    }, []);
112→
113→    // Compute viewport bounds in world coordinates
114→    const getViewportBounds = useCallback(() => {
115→        const scale = stageScale;
116→        const minX = (-stagePos.x) / scale;
117→        const minY = (-stagePos.y) / scale;
118→        const maxX = (stageSize.width - stagePos.x) / scale;
119→        const maxY = (stageSize.height - stagePos.y) / scale;
120→        // Add padding for stars near edges
121→        const pad = 200 / scale;
122→        return {
123→            minX: minX - pad,
124→            maxX: maxX + pad,
125→            minY: minY - pad,
126→            maxY: maxY + pad
127→        };
128→    }, [stagePos, stageScale, stageSize]);
129→
130→    // Debounced fetch
131→    useEffect(() => {
132→        if(debounceRef.current) clearTimeout(debounceRef.current);
133→
134→        debounceRef.current = setTimeout(async () => {
135→            const bounds = getViewportBounds();
136→            try {
137→                const result = await getUniversePosts(bounds.minX, bounds.maxX, bounds.minY, bounds.maxY, 200);
138→                if(result?.data){
139→                    setPosts(prev => {
140→                        const next = new Map(prev);
141→                        for(const post of result.data){
142→                            next.set(post.id, post);
143→                        }
144→                        return next;
145→                    });
146→                }
147→            } catch(err) {
148→                console.error('Failed to fetch universe posts:', err);
149→            }
150→        }, 400);
151→
152→        return () => {
153→            if(debounceRef.current) clearTimeout(debounceRef.current);
154→        };
155→    }, [stagePos, stageScale, stageSize, getViewportBounds]);
156→
157→    // Wheel zoom
158→    const handleWheel = useCallback((e) => {
159→        e.evt.preventDefault();
160→        const stage = stageRef.current;
161→        if(!stage) return;
162→
163→        const oldScale = stageScale;
164→        const pointer = stage.getPointerPosition();
165→        if(!pointer) return;
166→
167→        const scaleBy = 1.08;
168→        const direction = e.evt.deltaY > 0 ? -1 : 1;
169→        const newScale = Math.min(Math.max(direction > 0 ? oldScale * scaleBy : oldScale / scaleBy, 0.02), 5);
170→
171→        const mousePointTo = {
172→            x: (pointer.x - stagePos.x) / oldScale,
173→            y: (pointer.y - stagePos.y) / oldScale,
174→        };
175→
176→        setStageScale(newScale);
177→        setStagePos({
178→            x: pointer.x - mousePointTo.x * newScale,
179→            y: pointer.y - mousePointTo.y * newScale,
180→        });
181→    }, [stageScale, stagePos]);
182→
183→    // Touch pinch zoom
184→    const handleTouchMove = useCallback((e) => {
185→        const touch = e.evt;
186→        if(touch.touches.length !== 2) {
187→            lastPinchDist.current = null;
188→            return;
189→        }
190→
191→        const stage = stageRef.current;
192→        if(!stage) return;
193→
194→        e.evt.preventDefault();
195→
196→        const t1 = touch.touches[0];
197→        const t2 = touch.touches[1];
198→        const dist = Math.sqrt(Math.pow(t2.clientX - t1.clientX, 2) + Math.pow(t2.clientY - t1.clientY, 2));
199→
200→        if(lastPinchDist.current === null){
201→            lastPinchDist.current = dist;
202→            return;
203→        }
204→
205→        const oldScale = stageScale;
206→        const scale = Math.min(Math.max(oldScale * (dist / lastPinchDist.current), 0.02), 5);
207→        lastPinchDist.current = dist;
208→
209→        const center = {
210→            x: (t1.clientX + t2.clientX) / 2,
211→            y: (t1.clientY + t2.clientY) / 2,
212→        };
213→
214→        const mousePointTo = {
215→            x: (center.x - stagePos.x) / oldScale,
216→            y: (center.y - stagePos.y) / oldScale,
217→        };
218→
219→        setStageScale(scale);
220→        setStagePos({
221→            x: center.x - mousePointTo.x * scale,
222→            y: center.y - mousePointTo.y * scale,
223→        });
224→    }, [stageScale, stagePos]);
225→
226→    const handleTouchEnd = useCallback(() => {
227→        lastPinchDist.current = null;
228→    }, []);
229→
230→    // Star click handler
231→    const handleStarClick = useCallback((post) => {
232→        setSelectedPost(post);
233→        setPulsingId(post.id);
234→        setTimeout(() => setPulsingId(null), 400);
235→    }, []);
236→
237→    // Drag handlers
238→    const handleDragStart = useCallback(() => setIsDragging(true), []);
239→    const handleDragEnd = useCallback((e) => {
240→        setIsDragging(false);
241→        setStagePos({x: e.target.x(), y: e.target.y()});
242→    }, []);
243→
244→    // Navigate to post
245→    const handleReadPost = useCallback(() => {
246→        if(!selectedPost) return;
247→        navigate(`/home/post/${selectedPost.id}`);
248→    }, [selectedPost, navigate]);
249→
250→    // Memoize post array from map
251→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
252→
253→    // Determine which titles to show based on zoom
254→    const showTitles = stageScale > 0.5;
255→
256→    // Center coordinate display
257→    const centerWorld = useMemo(() => ({
258→        x: Math.round((stageSize.width / 2 - stagePos.x) / stageScale),
259→        y: Math.round((stageSize.height / 2 - stagePos.y) / stageScale),
260→    }), [stagePos, stageScale, stageSize]);
261→
262→    return (
263→        <div
264→            ref={containerRef}
265→            className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}
266→        >
267→            <button className={styles.backButton} onClick={() => navigate('/home')}>
268→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
269→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
270→                </svg>
271→                Back
272→            </button>
273→
274→            <div className={styles.coordsLabel}>
275→                {centerWorld.x}, {centerWorld.y}
276→            </div>
277→
278→            <Stage
279→                ref={stageRef}
280→                width={stageSize.width}
281→                height={stageSize.height}
282→                draggable
283→                x={stagePos.x}
284→                y={stagePos.y}
285→                scaleX={stageScale}
286→                scaleY={stageScale}
287→                onWheel={handleWheel}
288→                onDragStart={handleDragStart}
289→                onDragEnd={handleDragEnd}
290→                onTouchMove={handleTouchMove}
291→                onTouchEnd={handleTouchEnd}
292→            >
293→                <Layer>
294→                    {postArray.map((post) => {
295→                        const userId = post.users?.id;
296→                        const color = getStarColor(userId);
297→                        const likeCount = Array.isArray(post.likes) && post.likes[0]?.count != null
298→                            ? post.likes[0].count
299→                            : 0;
300→                        const radius = getStarRadius(likeCount);
301→                        const isPulsing = pulsingId === post.id;
302→
303→                        return (
304→                            <Group
305→                                key={post.id}
306→                                x={post.universe_x}
307→                                y={post.universe_y}
308→                                onClick={() => handleStarClick(post)}
309→                                onTap={() => handleStarClick(post)}
310→                                scaleX={isPulsing ? 1.8 : 1}
311→                                scaleY={isPulsing ? 1.8 : 1}
312→                            >
313→                                <Circle
314→                                    radius={radius}
315→                                    fill={color}
316→                                    shadowColor={color}
317→                                    shadowBlur={16}
318→                                    shadowOpacity={0.8}
319→                                    hitStrokeWidth={12}
320→                                />
321→                                {showTitles && post.title && (
322→                                    <Text
323→                                        text={post.title.length > 24 ? post.title.slice(0, 22) + '...' : post.title}
324→                                        y={radius + 6}
325→                                        fontSize={10}
326→                                        fill="rgba(255,255,255,0.6)"
327→                                        align="center"
328→                                        width={120}
329→                                        offsetX={60}
330→                                    />
331→                                )}
332→                            </Group>
333→                        );
334→                    })}
335→                </Layer>
336→            </Stage>
337→
338→            {selectedPost && (
339→                <div className={styles.previewPanel}>
340→                    <div className={styles.previewAuthor}>
341→                        <img
342→                            className={styles.previewAvatar}
343→                            src={selectedPost.users?.image_url || '/assets/profile.jpg'}
344→                            alt=""
345→                        />
346→                        <span className={styles.previewAuthorName}>
347→                            {selectedPost.users?.name || 'Anonymous'}
348→                        </span>
349→                    </div>
350→                    <div className={styles.previewTitle}>{selectedPost.title}</div>
351→                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
352→                    <div className={styles.previewLikes}>
353→                        {Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count
354→                            ? `${selectedPost.likes[0].count} like${selectedPost.likes[0].count !== 1 ? 's' : ''}`
355→                            : '0 likes'}
356→                    </div>
357→                    <button className={styles.previewReadBtn} onClick={handleReadPost}>
358→                        Read
359→                    </button>
360→                </div>
361→            )}
362→        </div>
363→    );
364→};
