#### Phase 1: Seeded Procedural Generation

**File: `client/src/components/Universe/utils/proceduralGeneration.js`** (new)

This module provides deterministic background content that all clients render identically.

```js
// Mulberry32 seeded PRNG -- fast, deterministic, 32-bit state
const mulberry32 = (seed) => {
    return () => {
        seed |= 0; seed = seed + 0x6D2B79F5 | 0;
        let t = Math.imul(seed ^ seed >>> 15, 1 | seed);
        t = t + Math.imul(t ^ t >>> 7, 61 | t) ^ t;
        return ((t ^ t >>> 14) >>> 0) / 4294967296;
    };
};

export const generateDeepSpaceStars = (count = 2000, seed = 42) => {
    const rng = mulberry32(seed);
    const stars = [];
    // Range: 10000x10000 centered on origin. Since parallax = 0.1,
    // this covers ~100000 world-unit range (the full [-50000, +50000] pan)
    const RANGE = 50000;
    for (let i = 0; i < count; i++) {
        stars.push({
            x: (rng() - 0.5) * RANGE * 2,
            y: (rng() - 0.5) * RANGE * 2,
            radius: 0.5 + rng() * 1.5,     // tiny: 0.5-2px
            opacity: 0.2 + rng() * 0.5,     // dim: 0.2-0.7
            color: `rgba(255, 255, 255, ${0.3 + rng() * 0.4})`
        });
    }
    return stars;
};

export const generateMidGalaxyStars = (count = 800, seed = 137) => {
    const rng = mulberry32(seed);
    const stars = [];
    const RANGE = 50000;
    for (let i = 0; i < count; i++) {
        stars.push({
            x: (rng() - 0.5) * RANGE * 2,
            y: (rng() - 0.5) * RANGE * 2,
            radius: 1 + rng() * 3,          // small: 1-4px
            opacity: 0.15 + rng() * 0.35,
            color: STAR_COLORS[Math.floor(rng() * STAR_COLORS.length)]
        });
    }
    return stars;
};

export const generateNebulae = (count = 18, seed = 256) => {
    const rng = mulberry32(seed);
    const nebulae = [];
    const RANGE = 40000;
    for (let i = 0; i < count; i++) {
        const colorIdx = Math.floor(rng() * STAR_COLORS.length);
        nebulae.push({
            x: (rng() - 0.5) * RANGE * 2,
            y: (rng() - 0.5) * RANGE * 2,
            radius: 200 + rng() * 600,       // large: 200-800px world units
            color: STAR_COLORS[colorIdx],
            opacity: 0.03 + rng() * 0.06,    // very subtle: 0.03-0.09
            blurRadius: 100 + rng() * 150     // heavy blur: 100-250
        });
    }
    return nebulae;
};
```

Key design decision: The range for deep space stars is set large (100k total spread) because with `parallaxFactor = 0.1`, these stars shift very slowly. The mid-galaxy range is similarly large. Both are pre-generated once and memoized.

