#### Phase 2: useUniverseCamera Hook

**File: `client/src/components/Universe/hooks/useUniverseCamera.js`** (new)

This is the most critical architectural change. It replaces the `<Stage draggable>` pattern with a world-coordinate camera that computes per-layer positions.

**State model change:**

Current (screen-space):
```
stagePos = {x: screenOffsetX, y: screenOffsetY}  // screen pixels
stageScale = zoomLevel
```

New (world-space):
```
camera = {x: worldX, y: worldY}  // world coordinates of screen center
zoom = zoomLevel
```

**Conversion formulas:**

The relationship between old and new models:
```
camera.x = (screenW/2 - stagePos.x) / stageScale
camera.y = (screenH/2 - stagePos.y) / stageScale
```

**Hook API:**

```js
export const useUniverseCamera = (userId) => {
    // State
    const [camera, setCamera] = useState({x, y});  // world coords
    const [zoom, setZoom] = useState(initialZoom);
    const [stageSize, setStageSize] = useState({...});
    const [isDragging, setIsDragging] = useState(false);

    // Refs for drag tracking
    const dragStartRef = useRef(null);      // {pointer, camera} at drag start
    const lastPinchRef = useRef(null);      // {dist, center} for pinch
    const stageRef = useRef(null);          // Konva stage ref

    // Window resize listener (same as current)
    useEffect(() => { /* resize handler */ }, []);

    // --- Pointer-based drag (replaces Stage draggable) ---
    const handlePointerDown = useCallback((e) => {
        // Only start drag on primary button (mouse) or single touch
        if (e.evt.touches && e.evt.touches.length > 1) return;
        const pointer = stageRef.current?.getPointerPosition();
        if (!pointer) return;
        dragStartRef.current = {
            pointerX: pointer.x,
            pointerY: pointer.y,
            cameraX: camera.x,
            cameraY: camera.y
        };
        setIsDragging(true);
    }, [camera]);

    const handlePointerMove = useCallback((e) => {
        if (!dragStartRef.current) return;
        // If pinching (2 touches), don't drag
        if (e.evt.touches && e.evt.touches.length > 1) return;
        const pointer = stageRef.current?.getPointerPosition();
        if (!pointer) return;
        const dx = pointer.x - dragStartRef.current.pointerX;
        const dy = pointer.y - dragStartRef.current.pointerY;
        setCamera({
            x: dragStartRef.current.cameraX - dx / zoom,
            y: dragStartRef.current.cameraY - dy / zoom
        });
    }, [zoom]);

    const handlePointerUp = useCallback(() => {
        dragStartRef.current = null;
        setIsDragging(false);
    }, []);

    // --- Wheel zoom (zoom-to-cursor) ---
    const handleWheel = useCallback((e) => {
        e.evt.preventDefault();
        const pointer = stageRef.current?.getPointerPosition();
        if (!pointer) return;

        const scaleBy = 1.08;
        const direction = e.evt.deltaY > 0 ? -1 : 1;
        const oldZoom = zoom;
        const newZoom = Math.min(Math.max(
            direction > 0 ? oldZoom * scaleBy : oldZoom / scaleBy,
            0.02
        ), 5);

        // Zoom-to-cursor: adjust camera so the world point under cursor stays fixed
        const cursorWorldX = camera.x + (pointer.x - stageSize.width / 2) / oldZoom;
        const cursorWorldY = camera.y + (pointer.y - stageSize.height / 2) / oldZoom;
        setCamera({
            x: cursorWorldX - (pointer.x - stageSize.width / 2) / newZoom,
            y: cursorWorldY - (pointer.y - stageSize.height / 2) / newZoom
        });
        setZoom(newZoom);
    }, [zoom, camera, stageSize]);

    // --- Touch pinch zoom ---
    const handleTouchMove = useCallback((e) => {
        const touch = e.evt;
        if (touch.touches.length !== 2) {
            lastPinchRef.current = null;
            return;
        }
        e.evt.preventDefault();

        const t1 = touch.touches[0];
        const t2 = touch.touches[1];
        const dist = Math.hypot(t2.clientX - t1.clientX, t2.clientY - t1.clientY);
        const center = {
            x: (t1.clientX + t2.clientX) / 2,
            y: (t1.clientY + t2.clientY) / 2
        };

        if (!lastPinchRef.current) {
            lastPinchRef.current = { dist, center };
            // Cancel single-finger drag while pinching
            dragStartRef.current = null;
            setIsDragging(false);
            return;
        }

        const oldZoom = zoom;
        const newZoom = Math.min(Math.max(
            oldZoom * (dist / lastPinchRef.current.dist),
            0.02
        ), 5);

        // Zoom-to-pinch-center
        const centerWorldX = camera.x + (center.x - stageSize.width / 2) / oldZoom;
        const centerWorldY = camera.y + (center.y - stageSize.height / 2) / oldZoom;
        setCamera({
            x: centerWorldX - (center.x - stageSize.width / 2) / newZoom,
            y: centerWorldY - (center.y - stageSize.height / 2) / newZoom
        });
        setZoom(newZoom);
        lastPinchRef.current = { dist, center };
    }, [zoom, camera, stageSize]);

    const handleTouchEnd = useCallback(() => {
        lastPinchRef.current = null;
    }, []);

    // --- Per-layer position computation ---
    const getLayerProps = useCallback((parallaxFactor) => ({
        x: stageSize.width / 2 - camera.x * parallaxFactor * zoom,
        y: stageSize.height / 2 - camera.y * parallaxFactor * zoom,
        scaleX: zoom,
        scaleY: zoom
    }), [camera, zoom, stageSize]);

    // --- Viewport bounds for data fetching ---
    const getViewportBounds = useCallback(() => {
        const halfW = (stageSize.width / 2) / zoom;
        const halfH = (stageSize.height / 2) / zoom;
        const pad = 200 / zoom;
        return {
            minX: camera.x - halfW - pad,
            maxX: camera.x + halfW + pad,
            minY: camera.y - halfH - pad,
            maxY: camera.y + halfH + pad
        };
    }, [camera, zoom, stageSize]);

    // --- Center world coords for display ---
    const centerWorld = useMemo(() => ({
        x: Math.round(camera.x),
        y: Math.round(camera.y)
    }), [camera]);

    return {
        stageRef,
        stageSize,
        camera,
        zoom,
        isDragging,
        centerWorld,
        getLayerProps,
        getViewportBounds,
        // Stage event handlers
        stageEvents: {
            onMouseDown: handlePointerDown,
            onMouseMove: handlePointerMove,
            onMouseUp: handlePointerUp,
            onWheel: handleWheel,
            onTouchStart: handlePointerDown,
            onTouchMove: handleTouchMove,
            onTouchEnd: handleTouchEnd
        }
    };
};
```

**Critical implementation notes for the hook:**

1. The Stage must NOT be `draggable`. All panning is handled via pointer events.
2. `handlePointerDown` stores the initial pointer screen position and camera world position. `handlePointerMove` computes the delta in screen pixels, divides by zoom to get world units, and subtracts from the stored camera position. This means the drag is smooth with no Konva internal state conflicts.
3. Pinch zoom cancels any active single-finger drag to prevent jitter.
4. `getLayerProps(1.0)` gives the interactive layer its position. `getLayerProps(0.4)` gives mid-galaxy. `getLayerProps(0.1)` gives deep space. Each layer gets its own independent `x`/`y` offset.
5. The initial camera state is computed from `userHomeCoords(userId)` for logged-in users (centering camera on their home world coords), or `{x: 0, y: 0}` with `GUEST_SCALE` zoom for guests.

**Initial camera computation:**
```js
const computeInitialCamera = (userId) => {
    if (!userId) return { x: 0, y: 0, zoom: GUEST_SCALE };
    const home = userHomeCoords(userId);
    return { x: home.x, y: home.y, zoom: HOME_SCALE };
};
```

This is simpler than the current screen-space calculation because with the world-coordinate model, the camera center IS the world coordinate directly.

